namespace sv_e1384e8a6f5543dab67e0afd968f1921.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTime Timestamp { get; set; }
}

using sv_e1384e8a6f5543dab67e0afd968f1921.Client.Models;

namespace sv_e1384e8a6f5543dab67e0afd968f1921.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_e1384e8a6f5543dab67e0afd968f1921.Client.Models;
using sv_e1384e8a6f5543dab67e0afd968f1921.Client.Services;

namespace sv_e1384e8a6f5543dab67e0afd968f1921.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = DateTime.Today.AddDays(2),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = DateTime.Today.AddDays(-3) },
                new StatusUpdate { Description = "Arrived at sorting facility", Location = "Philadelphia, PA", Timestamp = DateTime.Today.AddDays(-2) },
                new StatusUpdate { Description = "Departed facility", Location = "Philadelphia, PA", Timestamp = DateTime.Today.AddDays(-1).AddHours(6) },
                new StatusUpdate { Description = "In transit", Location = "Chicago, IL", Timestamp = DateTime.Today.AddHours(-4) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = DateTime.Today.AddDays(-1),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = DateTime.Today.AddDays(-5) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = DateTime.Today.AddDays(-3) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = DateTime.Today.AddDays(-1).AddHours(8) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = DateTime.Today.AddDays(-1).AddHours(14) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = DateTime.Today.AddDays(5),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = DateTime.Today.AddHours(-2) },
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_e1384e8a6f5543dab67e0afd968f1921.Client.Models;

namespace sv_e1384e8a6f5543dab67e0afd968f1921.Client.Services;

public class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_e1384e8a6f5543dab67e0afd968f1921.Client.Models
@using sv_e1384e8a6f5543dab67e0afd968f1921.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipments> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        No shipment found for tracking number <strong>@TrackingNumber</strong>.
    </div>
}
else
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl class="row">
        <dt class="col-sm-3">Status</dt>
        <dd class="col-sm-9">@_shipment.Status</dd>

        <dt class="col-sm-3">Location</dt>
        <dd class="col-sm-9">@_shipment.Location</dd>

        <dt class="col-sm-3">Estimated Delivery</dt>
        <dd class="col-sm-9">@(_shipment.EstimatedDelivery?.ToString("D") ?? "—")</dd>
    </dl>

    @if (_shipment.StatusUpdates.Count > 0)
    {
        <h4>Tracking History</h4>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Description</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;
    private string? _loadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(_loadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase) && !_loading)
            return;

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        _loadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was intentionally cancelled; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
